function Timestamped(constructor: Function) {
  constructor.prototype.createdAt = new Date();
}

@Timestamped
class User {
  name: string;
  constructor(name: string) {
    this.name = name;
  }
}

const user = new User('Alice');
console.log(user.name); // Alice
console.log((user as any).createdAt); // Current date and time

function Log(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyKey} with arguments:`, args);
    const result = originalMethod.apply(this, args);
    console.log(`${propertyKey} returned:`, result);
    return result;
  };
  return descriptor;
}

class Calculator {
  @Log
  add(a: number, b: number): number {
    return a + b;
  }
}

const calc = new Calculator();
calc.add(2, 3);

type Input = string | number;

function processInput(input: Input) {
  if (typeof input === 'string') {
    console.log('String input:', input.toUpperCase());
  } else if (typeof input === 'number') {
    console.log('Number input:', input.toFixed(2));
  } else {
    // Unexpected case - this should never happen
    console.error('Unexpected input type:', input);
  }
}

processInput('hello');
processInput(42);
// @ts-expect-error simulating unexpected input
processInput(true);

function assertNever(x: never): never {
  throw new Error("Unexpected value: " + x);
}

function processInputExhaustive(input: Input) {
  if (typeof input === 'string') {
    console.log('String input:', input.toUpperCase());
  } else if (typeof input === 'number') {
    console.log('Number input:', input.toFixed(2));
  } else {
    assertNever(input); // This line helps ensure that all union types are handled
  }
}

function isString(input: unknown): input is string {
  return typeof input === 'string';
}

function safeProcess(input: unknown) {
  if (isString(input)) {
    console.log('Safe string input:', input.toUpperCase());
  } else {
    console.error('Invalid input type!');
  }
}

def process_large_file(file_path):
    with open(file_path, 'r', encoding='utf-8') as file:
        for line_number, line in enumerate(file, start=1):
            line = line.strip()
            if not line:
                # Skip empty lines
                continue
            try:
                # Example: process the line (e.g., parse data)
                print(f"Line {line_number}: {line[:50]}...")  # Preview first 50 chars
            except Exception as e:
                print(f"Error processing line {line_number}: {e}")

# Usage
# process_large_file('path/to/large_file.txt')

def process_file_in_chunks(file_path, chunk_size=4096):
    with open(file_path, 'rb') as file:
        while True:
            chunk = file.read(chunk_size)
            if not chunk:
                break
            # Process binary chunk here
            print(f"Read chunk of size {len(chunk)} bytes")

# Usage
# process_file_in_chunks('path/to/large_binary_file.bin')

